// code — the launcher picker + profile generator, as a Bubble Tea TUI.
//
// Manifest (generated by omp-configured, so this binary stays generic):
//
//	CODE_PROFILES  : TSV  name \t blurb \t detail \t group \t exe \t colorHex \t glyph
//	CODE_ROUTES    : routes.plain (managed profile routing blocks, keyed by name)
//	CODE_GENERATED : generated.plain (facet-grid blocks, keyed by combo id)
//	CODE_USAGE     : optional command (space-split) that prints `omp usage --json`
package main

import (
	"bufio"
	"encoding/json"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"sort"
	"strings"
	"syscall"
	"time"

	"github.com/charmbracelet/bubbles/help"
	"github.com/charmbracelet/bubbles/key"
	"github.com/charmbracelet/bubbles/spinner"
	"github.com/charmbracelet/bubbles/viewport"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// ── keybindings (drive both input handling and the bubbles/help footer) ───────
type keyMap struct {
	Switch, Move, Change, Depth, Refresh, Collapse, Launch, Help, Quit key.Binding
}

func (k keyMap) ShortHelp() []key.Binding {
	return []key.Binding{k.Switch, k.Move, k.Change, k.Launch, k.Help, k.Quit}
}
func (k keyMap) FullHelp() [][]key.Binding {
	return [][]key.Binding{
		{k.Switch, k.Move, k.Change},
		{k.Depth, k.Refresh, k.Collapse},
		{k.Launch, k.Help, k.Quit},
	}
}

var keys = keyMap{
	Switch:   key.NewBinding(key.WithKeys("tab"), key.WithHelp("tab", "generator ⇄ profiles")),
	Move:     key.NewBinding(key.WithKeys("up", "down", "j", "k"), key.WithHelp("↑↓", "move")),
	Change:   key.NewBinding(key.WithKeys("left", "right", "h", "l"), key.WithHelp("←→", "change")),
	Depth:    key.NewBinding(key.WithKeys("f"), key.WithHelp("f", "depth lead/full")),
	Refresh:  key.NewBinding(key.WithKeys("r"), key.WithHelp("r", "refresh usage")),
	Collapse: key.NewBinding(key.WithKeys("p"), key.WithHelp("p", "collapse")),
	Launch:   key.NewBinding(key.WithKeys("enter"), key.WithHelp("⏎", "launch")),
	Help:     key.NewBinding(key.WithKeys("?"), key.WithHelp("?", "more")),
	Quit:     key.NewBinding(key.WithKeys("q", "esc", "ctrl+c"), key.WithHelp("q", "quit")),
}

// ── palette ──────────────────────────────────────────────────────────────────
const (
	cDim     = "#78829b"
	cGrp     = "#69727e"
	cAcc     = "#ff9f52"
	cBord    = "#3a4453"
	cHead    = "#9aa4b1"
	cSelBg   = "#1b212b"
	cGptSoft = "#6e91be"
	cClaSoft = "#c3a078"
	cRed     = "#d05c60"
	cGreen   = "#78c8aa"
)

// Emoji-presentation glyphs pinned to text presentation (U+FE0E) so terminals
// render them 1-cell — matching the width the layout math assumes.
const (
	gWarn   = "⚠︎"
	gBroken = "✗︎"
	gReset  = "↻︎"
)

var (
	stDim  = lipgloss.NewStyle().Foreground(lipgloss.Color(cDim))
	stGrp  = lipgloss.NewStyle().Foreground(lipgloss.Color(cGrp))
	stHead = lipgloss.NewStyle().Foreground(lipgloss.Color(cHead))
	stWarn = lipgloss.NewStyle().Foreground(lipgloss.Color(cAcc))
	stBrk  = lipgloss.NewStyle().Foreground(lipgloss.Color(cRed))
	// a maxed/unauthed model in a chain: struck through + dimmed, so you can
	// see at a glance which lead gets skipped for the fallback beneath it.
	stStruck = lipgloss.NewStyle().Strikethrough(true).Faint(true).Foreground(lipgloss.Color(cDim))

	modelRe = regexp.MustCompile(`(gpt|claude)[A-Za-z0-9._-]*:(minimal|low|medium|high|xhigh|max)`)
	gptRe   = regexp.MustCompile(`\b(GPT|gpt|OpenAI|Codex|Spark|spark|Sol|Terra|Luna|Nano|nano)\b`)
	claRe   = regexp.MustCompile(`\b(Claude|claude|Anthropic|Opus|opus|Sonnet|sonnet|Haiku|haiku|Fable|fable)\b`)
)

// ── colourisers ──────────────────────────────────────────────────────────────
func lvl(s string) int {
	switch s {
	case "minimal":
		return 0
	case "low":
		return 1
	case "medium":
		return 2
	case "high":
		return 3
	case "xhigh":
		return 4
	}
	return 5
}

func shortModel(name string) string {
	if name == "gpt-5.4" {
		return name
	}
	p := strings.Split(name, "-")
	if strings.HasPrefix(name, "claude") && len(p) > 1 {
		return p[1]
	}
	return p[len(p)-1]
}

func clampByte(x float64) int {
	v := int(x)
	if v > 255 {
		return 255
	}
	if v < 0 {
		return 0
	}
	return v
}

func paintModel(tok string) string {
	i := strings.LastIndex(tok, ":")
	name, level := tok[:i], tok[i+1:]
	var br, bg, bb float64
	if strings.HasPrefix(tok, "gpt") {
		br, bg, bb = 110, 170, 240
	} else {
		br, bg, bb = 240, 160, 105
	}
	f := 0.60 + float64(lvl(level))*0.088
	col := lipgloss.Color(fmt.Sprintf("#%02x%02x%02x", clampByte(br*f), clampByte(bg*f), clampByte(bb*f)))
	return lipgloss.NewStyle().Foreground(col).Render(shortModel(name) + ":" + level)
}

func colorizeRoute(line string) string { return modelRe.ReplaceAllStringFunc(line, paintModel) }

// flavorize tints GPT-family words blue and Claude-family words orange over a
// dim base, with raw ANSI (keyword→colour→back to dim), like the gawk original.
const (
	ansiDim = "\x1b[38;2;120;130;145m"
	ansiGpt = "\x1b[38;2;110;145;190m"
	ansiCla = "\x1b[38;2;195;160;120m"
	ansiRst = "\x1b[0m"
)

func flavorize(s string) string {
	s = gptRe.ReplaceAllString(s, ansiGpt+"$1"+ansiDim)
	s = claRe.ReplaceAllString(s, ansiCla+"$1"+ansiDim)
	return ansiDim + s + ansiRst
}

// providerOf maps a short/long model name to its quota bucket.
func bucketOf(model string) string {
	m := model
	if i := strings.IndexByte(m, ':'); i >= 0 {
		m = m[:i]
	}
	switch {
	case strings.Contains(m, "fable"):
		return "claude-fable"
	case strings.Contains(m, "spark"):
		return "codex-spark"
	case strings.Contains(m, "claude"), strings.Contains(m, "sonnet"),
		strings.Contains(m, "haiku"), strings.Contains(m, "opus"):
		return "claude-main"
	}
	return "codex-main"
}

// ── data ─────────────────────────────────────────────────────────────────────
type profile struct {
	name, blurb, detail, group, exe, color, glyph string
}

func loadProfiles(path string) []profile {
	f, err := os.Open(path)
	if err != nil {
		return nil
	}
	defer f.Close()
	var out []profile
	sc := bufio.NewScanner(f)
	sc.Buffer(make([]byte, 1024*64), 1024*64)
	for sc.Scan() {
		p := strings.Split(sc.Text(), "\t")
		for len(p) < 7 {
			p = append(p, "")
		}
		out = append(out, profile{p[0], p[1], p[2], p[3], p[4], p[5], p[6]})
	}
	return out
}

// loadBlocks parses a routes/generated page into name -> role rows.
func loadBlocks(path string) map[string][]string {
	blocks := map[string][]string{}
	f, err := os.Open(path)
	if err != nil {
		return blocks
	}
	defer f.Close()
	sc := bufio.NewScanner(f)
	sc.Buffer(make([]byte, 1024*128), 1024*128)
	var cur string
	for sc.Scan() {
		line := sc.Text()
		if line == "" {
			cur = ""
			continue
		}
		if line[0] != ' ' {
			if fs := strings.Fields(line); len(fs) > 0 {
				cur = fs[0]
				blocks[cur] = nil
			}
			continue
		}
		if cur != "" {
			blocks[cur] = append(blocks[cur], line)
		}
	}
	return blocks
}

// ── usage + availability ─────────────────────────────────────────────────────
type usageWin struct {
	label string
	pct   int
	tier  string
	secs  int64 // seconds until reset (relative)
	dur   int64 // window length in seconds
	prov  string
}

type availability struct {
	bucket map[string]string // bucket -> "ok" | "maxed" | "unauthed"
	reset  map[string]int64
	wins   []usageWin
	ok     bool
}

func loadAvailability(cmd string) availability {
	a := availability{bucket: map[string]string{}, reset: map[string]int64{}}
	if cmd == "" {
		return a
	}
	parts := strings.Fields(cmd)
	out, err := exec.Command(parts[0], parts[1:]...).Output()
	if err != nil || len(out) == 0 {
		return a
	}
	var doc struct {
		Reports []struct {
			Provider string `json:"provider"`
			Limits   []struct {
				Label string `json:"label"`
				Scope struct {
					Tier string `json:"tier"`
				} `json:"scope"`
				Amount struct {
					UsedFraction float64 `json:"usedFraction"`
				} `json:"amount"`
				Window struct {
					ResetsAt   int64 `json:"resetsAt"`
					DurationMs int64 `json:"durationMs"`
				} `json:"window"`
			} `json:"limits"`
		} `json:"reports"`
	}
	if json.Unmarshal(out, &doc) != nil {
		return a
	}
	a.ok = true
	provSeen := map[string]bool{}
	now := time.Now().Unix()
	for _, r := range doc.Reports {
		provSeen[r.Provider] = true
		for _, l := range r.Limits {
			pct := int(l.Amount.UsedFraction*100 + 0.5)
			a.wins = append(a.wins, usageWin{l.Label, pct, l.Scope.Tier, l.Window.ResetsAt/1000 - now, l.Window.DurationMs / 1000, r.Provider})
			bkt := bucketForProviderTier(r.Provider, l.Scope.Tier)
			if bkt == "" {
				continue
			}
			if pct >= 100 {
				a.bucket[bkt] = "maxed"
				a.reset[bkt] = l.Window.ResetsAt/1000 - now
			} else if a.bucket[bkt] != "maxed" {
				a.bucket[bkt] = "ok"
			}
		}
	}
	for _, b := range []string{"codex-main", "codex-spark", "claude-main", "claude-fable"} {
		p := "openai-codex"
		if strings.HasPrefix(b, "claude") {
			p = "anthropic"
		}
		if !provSeen[p] {
			a.bucket[b] = "unauthed"
		} else if _, ok := a.bucket[b]; !ok {
			a.bucket[b] = "ok"
		}
	}
	return a
}

func bucketForProviderTier(prov, tier string) string {
	if prov == "openai-codex" {
		if tier == "spark" {
			return "codex-spark"
		}
		if tier == "" || tier == "-" {
			return "codex-main"
		}
	}
	if prov == "anthropic" {
		if tier == "fable" {
			return "claude-fable"
		}
		if tier == "" || tier == "-" {
			return "claude-main"
		}
	}
	return ""
}

func (a availability) down(bucket string) bool {
	return a.bucket[bucket] == "maxed" || a.bucket[bucket] == "unauthed"
}

func fmtSecs(s int64) string {
	if s <= 0 {
		return "now"
	}
	switch {
	case s >= 86400:
		return fmt.Sprintf("%dd", s/86400)
	case s >= 3600:
		return fmt.Sprintf("%dh", s/3600)
	case s >= 60:
		return fmt.Sprintf("%dm", s/60)
	}
	return fmt.Sprintf("%ds", s)
}

func (a availability) note() string {
	label := map[string]string{"codex-main": "Codex", "codex-spark": "Spark", "claude-main": "Claude", "claude-fable": "Fable"}
	seen := map[string]bool{}
	var parts []string
	for _, b := range []string{"codex-main", "codex-spark", "claude-main", "claude-fable"} {
		if !a.down(b) {
			continue
		}
		var n string
		if a.bucket[b] == "maxed" {
			n = fmt.Sprintf("%s maxed · %s %s", label[b], gReset, fmtSecs(a.reset[b]))
		} else if strings.HasPrefix(b, "codex") {
			n = "needs Codex"
		} else {
			n = "needs Claude"
		}
		if !seen[n] {
			seen[n] = true
			parts = append(parts, n)
		}
	}
	return strings.Join(parts, " · ")
}

var substRoles = map[string]bool{"default": true, "task": true, "plan": true, "slow": true, "designer": true, "reviewer": true, "librarian": true}

// impact: "" (ok) | "degraded" | "broken", from a profile's routing block.
func (a availability) impact(rows []string) string {
	if !a.ok {
		return ""
	}
	defaultRunnable, defaultSeen, anyLeadDown := false, false, false
	for _, row := range rows {
		fields := strings.Fields(strings.TrimSpace(strings.ReplaceAll(row, "→", " ")))
		if len(fields) == 0 {
			continue
		}
		i := 0
		if fields[0] == "●" {
			i = 1
		}
		if i >= len(fields) {
			continue
		}
		role := fields[i]
		var models []string
		for _, f := range fields[i+1:] {
			if modelRe.MatchString(f) {
				models = append(models, f)
			}
		}
		if len(models) == 0 {
			continue
		}
		if substRoles[role] && a.down(bucketOf(models[0])) {
			anyLeadDown = true
		}
		if role == "default" {
			defaultSeen = true
			for _, m := range models {
				if !a.down(bucketOf(m)) {
					defaultRunnable = true
				}
			}
		}
	}
	if defaultSeen && !defaultRunnable {
		return "broken"
	}
	if anyLeadDown {
		return "degraded"
	}
	return ""
}

// ── routing render (depth: 0 lead · 1 full) ──────────────────────────────────
// renderRoute lays out each role's chain, wrapping cleanly at `width`: when a
// chain doesn't fit, it breaks after an arrow and the continuation is indented
// to align under the first model, so it reads as one hanging block rather than a
// ragged wrap. Down (maxed/unauthed) models are struck through.
func renderRoute(rows []string, depth int, a availability, width int) string {
	if width < 24 {
		width = 24
	}
	arrow := stDim.Render(" → ")
	var out []string
	for _, r := range rows {
		locs := modelRe.FindAllStringIndex(r, -1)
		if len(locs) == 0 { // a note/meta line with no models — pass through
			out = append(out, colorizeRoute(r))
			continue
		}
		label := r[:locs[0][0]] // role + its alignment padding, kept verbatim
		labelW := lipgloss.Width(label)
		indent := strings.Repeat(" ", labelW)

		type tok struct {
			text string
			down bool
		}
		var toks []tok
		for _, loc := range locs {
			mt := r[loc[0]:loc[1]]
			toks = append(toks, tok{mt, a.ok && a.down(bucketOf(mt))})
		}
		// how many to show: full → all; lead → primary, or up to the first live
		// model when the lead is down (the one that actually runs).
		last := len(toks) - 1
		if depth == 0 {
			last = 0
			for i, t := range toks {
				last = i
				if !t.down {
					break
				}
			}
		}
		// render a token as it displays (short name), returning the styled
		// string and its display width — struck if the model is down.
		render := func(t tok) (string, int) {
			c := strings.LastIndexByte(t.text, ':')
			short := shortModel(t.text[:c]) + t.text[c:]
			if t.down {
				s := stStruck.Render(short)
				return s, lipgloss.Width(s)
			}
			s := colorizeRoute(t.text) // paintModel shortens + colours
			return s, lipgloss.Width(s)
		}
		s0, w0 := render(toks[0])
		line, lineW := label+s0, labelW+w0
		for i := 1; i <= last; i++ {
			si, wi := render(toks[i])
			if lineW+3+wi > width { // won't fit — break after a trailing arrow
				out = append(out, line+stDim.Render(" →"))
				line, lineW = indent+si, labelW+wi
			} else {
				line += arrow + si
				lineW += 3 + wi
			}
		}
		out = append(out, line)
	}
	return strings.Join(out, "\n") + "\n"
}

// splitMeta peels the "thinking … · fallback … · advisor …" summary line off a
// routing block (if present), returning it trimmed plus the remaining role rows.
func splitMeta(rows []string) (string, []string) {
	if len(rows) > 0 && strings.Contains(rows[0], "·") && !modelRe.MatchString(rows[0]) {
		return strings.TrimSpace(rows[0]), rows[1:]
	}
	return "", rows
}

// ── generator facets ─────────────────────────────────────────────────────────
type facet struct {
	key    string
	values []string
	glyph  string
}

func facetDefs(glyphs map[string]string) []facet {
	return []facet{
		{"lane", []string{"gpt-only", "gpt-led", "mixed", "claude-led", "claude-only"}, glyphs["lane"]},
		{"model", []string{"fast", "normal", "smart"}, glyphs["model"]},
		{"thinking", []string{"low", "medium", "high", "xhigh"}, glyphs["thinking"]},
		// advisor as a power/cost dial: a quick glance, a proper review, or a
		// deep (expensive) audit — off spends nothing.
		{"advisor", []string{"off", "glance", "review", "audit"}, glyphs["advisor"]},
		{"fast", []string{"on", "off"}, glyphs["fast"]},
		{"spark", []string{"on", "off"}, glyphs["spark"]},
		{"fable", []string{"on", "off"}, glyphs["fable"]},
	}
}

// advisorChain synthesises the advisor role for a given intensity and lane. It
// keeps a pure lane pure (GPT advisor on a GPT-only pool) and otherwise reaches
// across to Claude, which gives the most independent second opinion.
// NOTE: these model names duplicate catalog knowledge from generate-profiles.py;
// the omp-configured wire-in should bake an advisor table there instead.
func advisorChain(level, lane string) []string {
	if lane == "gpt-only" {
		switch level {
		case "glance":
			return []string{"gpt-5.6-luna:low"}
		case "review":
			return []string{"gpt-5.6-terra:medium", "gpt-5.6-luna:low"}
		case "audit":
			return []string{"gpt-5.6-sol:high", "gpt-5.6-terra:high", "gpt-5.6-luna:low"}
		}
		return nil
	}
	switch level {
	case "glance":
		return []string{"claude-haiku-4-5:low"}
	case "review":
		return []string{"claude-sonnet-5:medium", "claude-haiku-4-5:low"}
	case "audit":
		return []string{"claude-opus-4-8:high", "claude-sonnet-5:high", "claude-haiku-4-5:low"}
	}
	return nil
}

// roleOf returns the role name of a routing row ("● task" → "task").
func roleOf(row string) string {
	f := strings.Fields(row)
	if len(f) > 0 && f[0] == "●" {
		f = f[1:]
	}
	if len(f) > 0 {
		return f[0]
	}
	return ""
}

// applyAdvisor replaces the baked advisor row with one synthesised from the
// chosen intensity (dropping it entirely when off), so the generated preview and
// the launched config both reflect the advisor facet.
func applyAdvisor(rows []string, level, lane string) []string {
	chain := advisorChain(level, lane)
	newRow := ""
	if len(chain) > 0 {
		newRow = "    advisor    " + strings.Join(chain, " → ")
	}
	var out []string
	replaced := false
	for _, r := range rows {
		if roleOf(r) == "advisor" {
			replaced = true
			if newRow != "" {
				out = append(out, newRow)
			}
			continue
		}
		out = append(out, r)
	}
	if !replaced && newRow != "" {
		out = append(out, newRow)
	}
	return out
}

// visibleFacets drops facets that don't apply to the current lane, so the
// generator only ever shows actionable options: no spark/fast on a Claude-only
// pool, no fable on a GPT-only pool.
func (m model) visibleFacets() []facet {
	lane := m.sel["lane"]
	var out []facet
	for _, f := range m.facets {
		if lane == "claude-only" && (f.key == "spark" || f.key == "fast") {
			continue
		}
		if lane == "gpt-only" && f.key == "fable" {
			continue
		}
		out = append(out, f)
	}
	return out
}

func comboID(sel map[string]string) string {
	lane := sel["lane"]
	sp, fb := sel["spark"], sel["fable"]
	if lane == "gpt-only" {
		fb = "off"
	}
	if lane == "claude-only" {
		sp = "off"
	}
	spid, faid := "nosp", "nofa"
	if sp == "on" {
		spid = "sp"
	}
	if fb == "on" {
		faid = "fa"
	}
	return fmt.Sprintf("%s_%s_%s_%s_%s", lane, sel["model"], sel["thinking"], spid, faid)
}

func laneColor(lane string) string {
	switch lane {
	case "gpt-only":
		return "#3f8ef0" // deeper blue — pure pool
	case "gpt-led":
		return "#7ab6ff" // lighter blue — leans GPT
	case "mixed":
		return "#aa96e1"
	case "claude-led":
		return "#ffb277" // lighter orange — leans Claude
	case "claude-only":
		return "#ff8534" // deeper orange — pure pool
	}
	return "#ff9f52"
}

func prefixed(model string) string {
	if strings.HasPrefix(model, "claude") {
		return "anthropic/" + model
	}
	return "openai-codex/" + model
}

// genConfigYAML reconstructs an omp config (modelRoles, fallback chains,
// thinking, advisor, and the priority tier when fast is on) from the generated
// routing block for the current facets — what Enter launches omp with.
func (m model) genConfigYAML() string {
	rows := applyAdvisor(m.generated[comboID(m.sel)], m.sel["advisor"], m.sel["lane"])
	var mr, fc strings.Builder
	advisorOn := false
	for _, r := range rows {
		f := strings.Fields(strings.ReplaceAll(r, "→", " "))
		i := 0
		if len(f) > 0 && f[0] == "●" {
			i = 1
		}
		if i >= len(f) {
			continue
		}
		role := f[i]
		var models []string
		for _, t := range f[i+1:] {
			if modelRe.MatchString(t) {
				models = append(models, t)
			}
		}
		if len(models) == 0 {
			continue
		}
		if role == "advisor" {
			advisorOn = true
		}
		mr.WriteString("  " + role + ": " + prefixed(models[0]) + "\n")
		if len(models) > 1 {
			var fbs []string
			for _, x := range models[1:] {
				fbs = append(fbs, prefixed(x))
			}
			fc.WriteString("    " + role + ": [" + strings.Join(fbs, ", ") + "]\n")
		}
	}
	var b strings.Builder
	b.WriteString("modelRoles:\n" + mr.String())
	b.WriteString("retry:\n  enabled: true\n  modelFallback: true\n  fallbackRevertPolicy: cooldown-expiry\n  fallbackChains:\n" + fc.String())
	b.WriteString("defaultThinkingLevel: " + m.sel["thinking"] + "\n")
	if advisorOn {
		b.WriteString("advisor:\n  enabled: true\n")
	} else {
		b.WriteString("advisor:\n  enabled: false\n")
	}
	if m.sel["fast"] == "on" && m.sel["lane"] != "claude-only" {
		b.WriteString("tier:\n  openai: priority\n")
	}
	return b.String()
}

// ── model ────────────────────────────────────────────────────────────────────
type viewKind int

const (
	pickerView viewKind = iota
	genView
)

// layout modes, chosen from the terminal size (unless the user collapses):
//
//	stacked   — wide+tall: generator on top, profiles below, preview on the right
//	split     — medium:    the focused list on the left, preview on the right
//	collapsed — narrow/‹p›: one full-width pane (list, or the result with showResult)
const (
	modeStacked = iota
	modeSplit
	modeCollapsed
)

// genRowWidth is the width needed to render the widest generator facet row (all
// options) on a single line — the minimum for the left panel.
func (m model) genRowWidth() int {
	max := 30
	for _, f := range m.facets { // widest over ALL facets, so width is lane-stable
		w := 14 // ▸ + glyph + spaces + padded label
		for _, v := range f.values {
			w += len(v) + 4
		}
		if w > max {
			max = w
		}
	}
	return max + 2
}

func (m model) mode() int {
	if m.collapse {
		return modeCollapsed
	}
	if m.w < m.genRowWidth()+33 { // no room for the gen list + a useful preview
		return modeCollapsed
	}
	return modeSplit
}

type model struct {
	profiles  []profile
	routes    map[string][]string
	generated map[string][]string
	avail     availability
	glyphs    map[string]string

	view       viewKind
	cursor     int
	depth      int // 0 lead · 1 full
	collapse   bool
	showResult bool // in collapsed mode: show the preview full-width

	facets []facet
	fcur   int
	sel    map[string]string

	vp       viewport.Model
	spin     spinner.Model
	help     help.Model
	w, h     int
	rdy      bool
	usageCmd string

	fetching    bool      // a usage fetch is in flight (manual or auto)
	nextRefresh time.Time // when the next auto-refresh fires

	chosen    string
	genConfig string // generated config YAML to launch omp with (generator Enter)
}

// usage auto-refreshes on this cadence; a 1s tick drives the countdown.
const refreshEvery = 5 * time.Minute

type refreshTickMsg struct{}

func tickCmd() tea.Cmd {
	return tea.Tick(time.Second, func(time.Time) tea.Msg { return refreshTickMsg{} })
}

// usageMsg carries availability fetched off the main thread so startup never
// blocks on `omp usage --json` (a network call).
type usageMsg availability

func fetchUsageCmd(cmd string) tea.Cmd {
	if cmd == "" {
		return nil
	}
	return func() tea.Msg { return usageMsg(loadAvailability(cmd)) }
}

func (m model) Init() tea.Cmd {
	if m.usageCmd == "" {
		return nil
	}
	return tea.Batch(fetchUsageCmd(m.usageCmd), m.spin.Tick, tickCmd())
}

func (m model) listW() int {
	// wide enough for the generator options on one line; capped so a very wide
	// terminal doesn't stretch the list needlessly.
	w := m.genRowWidth()
	if w > m.w-33 {
		w = m.w - 33
	}
	if w > 80 {
		w = 80
	}
	return w
}

// gradient bar (green→red), 10 cells, matching the fzf panel.
func barStr(p int) string {
	var r, g float64
	if p <= 50 {
		r, g = 90+float64(p)*3, 200
	} else {
		r, g = 235, 200-float64(p-50)*3
	}
	if r > 235 {
		r = 235
	}
	if g < 60 {
		g = 60
	}
	fill := (p*10 + 50) / 100
	if fill > 10 {
		fill = 10
	}
	if fill < 0 {
		fill = 0
	}
	filled := lipgloss.NewStyle().Foreground(lipgloss.Color(fmt.Sprintf("#%02x%02x46", clampByte(r), clampByte(g)))).Render(strings.Repeat("█", fill))
	return filled + stDim.Render(strings.Repeat("░", 10-fill))
}

func fmtReset(s int64) string {
	if s < 0 {
		s = 0
	}
	switch {
	case s >= 86400:
		return fmt.Sprintf("%dd%dh", s/86400, (s%86400)/3600)
	case s >= 3600:
		return fmt.Sprintf("%dh%dm", s/3600, (s%3600)/60)
	}
	return fmt.Sprintf("%dm", s/60)
}

func shortWin(l string) string {
	switch l {
	case "5 hours", "Claude 5 Hour":
		return "5h"
	case "7 days", "Claude 7 Day":
		return "7d"
	case "5 hours (Spark)":
		return "5h spark"
	case "7 days (Spark)":
		return "7d spark"
	case "Claude 7 Day (Fable)":
		return "7d fable"
	}
	return l
}

// refreshLine shows either the live countdown to the next auto-refresh or, while
// a fetch is in flight, a refreshing marker — plus the manual-refresh hint.
func (m *model) refreshLine() string {
	if m.fetching {
		return stDim.Render("  usage · ") + stWarn.Render(gReset+" refreshing…")
	}
	rem := time.Until(m.nextRefresh)
	if rem < 0 {
		rem = 0
	}
	s := int(rem.Seconds())
	return stDim.Render(fmt.Sprintf("  usage · next refresh %d:%02d · ", s/60, s%60)) +
		lipgloss.NewStyle().Foreground(lipgloss.Color(cHead)).Render("r") + stDim.Render(" now")
}

func (m *model) usagePanel() string {
	if !m.avail.ok {
		if m.usageCmd != "" {
			return stDim.Render("  " + m.spin.View() + " fetching usage…")
		}
		return ""
	}
	if len(m.avail.wins) == 0 {
		return ""
	}
	wins := append([]usageWin(nil), m.avail.wins...)
	provOrder := func(p string) int {
		switch p {
		case "openai-codex":
			return 0
		case "anthropic":
			return 1
		}
		return 2
	}
	tierOrder := func(t string) int {
		if t == "" || t == "-" {
			return 0
		}
		return 1
	}
	sort.SliceStable(wins, func(i, j int) bool {
		if o := provOrder(wins[i].prov) - provOrder(wins[j].prov); o != 0 {
			return o < 0
		}
		if o := tierOrder(wins[i].tier) - tierOrder(wins[j].tier); o != 0 {
			return o < 0
		}
		return wins[i].dur < wins[j].dur
	})
	blocks := map[string][]string{}
	var order []string
	for _, w := range wins {
		if _, ok := blocks[w.prov]; !ok {
			order = append(order, w.prov)
			pcol, pname := "#62a7ff", "Codex"
			if w.prov == "anthropic" {
				pcol, pname = "#ff9f52", "Claude"
			}
			blocks[w.prov] = []string{lipgloss.NewStyle().Foreground(lipgloss.Color(pcol)).Bold(true).Render(pname)}
		}
		blocks[w.prov] = append(blocks[w.prov], m.usageRow(w))
	}
	// side-by-side when there's horizontal room, else stacked. colW must fit the
	// widest row (label · bar · pct · ↻reset · note) without wrapping the note.
	const colW = 49
	if len(order) > 1 && m.w >= colW*len(order) {
		var cols []string
		for _, p := range order {
			cols = append(cols, lipgloss.NewStyle().Width(colW).Render(strings.Join(blocks[p], "\n")))
		}
		return m.refreshLine() + "\n" + lipgloss.JoinHorizontal(lipgloss.Top, cols...)
	}
	var lines []string
	for _, p := range order {
		lines = append(lines, blocks[p]...)
	}
	return m.refreshLine() + "\n" + strings.Join(lines, "\n")
}

func (m *model) usageRow(w usageWin) string {
	note := ""
	if w.pct >= 80 {
		note = "  " + stWarn.Render("tight")
	}
	if w.pct >= 100 {
		note = "  " + stBrk.Render("maxed")
	}
	if w.tier == "spark" && w.pct == 0 {
		note = "  " + lipgloss.NewStyle().Foreground(lipgloss.Color(cGreen)).Render("idle")
	}
	reset := stDim.Render(gReset + " " + fmtReset(w.secs))
	if w.dur > 0 && w.secs*10 < w.dur {
		reset = lipgloss.NewStyle().Foreground(lipgloss.Color("#c8d0dc")).Bold(true).Render(gReset + " " + fmtReset(w.secs))
	} else if w.dur > 0 && w.secs*4 < w.dur {
		reset = lipgloss.NewStyle().Foreground(lipgloss.Color("#c8d0dc")).Render(gReset + " " + fmtReset(w.secs))
	}
	return fmt.Sprintf("  %-9s %s %3d%% used  %s%s", shortWin(w.label), barStr(w.pct), w.pct, reset, note)
}

func (m *model) syncPreview() {
	if !m.rdy || m.collapse {
		return
	}
	rw := m.vp.Width
	// routing rule carries the depth state, so `f` (lead ⇄ full) is discoverable.
	depthLbl := "lead"
	if m.depth == 1 {
		depthLbl = "full"
	}
	rHead := "── routing · " + depthLbl + " "
	rule := stDim.Render("── routing · ") + stHead.Render(depthLbl) +
		stDim.Render(" "+strings.Repeat("─", max(4, rw-lipgloss.Width(rHead))))
	var b strings.Builder
	if m.view == pickerView {
		p := m.profiles[m.cursor]
		nm := lipgloss.NewStyle().Foreground(lipgloss.Color(p.color)).Bold(true).Render(p.name)
		b.WriteString(nm + "  " + flavorize(p.blurb) + "\n\n")
		b.WriteString(flavorize(p.detail) + "\n")
		if imp := m.avail.impact(m.routes[p.name]); imp != "" {
			b.WriteString("\n")
			if imp == "broken" {
				b.WriteString(stBrk.Render(gBroken+" "+m.avail.note()+" — default has no live fallback") + "\n")
			} else {
				b.WriteString(stWarn.Render(gWarn+" "+m.avail.note()+" — runs on a fallback") + "\n")
			}
		}
		meta, roles := splitMeta(m.routes[p.name])
		b.WriteString("\n")
		if meta != "" {
			b.WriteString(stDim.Render(meta) + "\n")
		}
		b.WriteString(rule + "\n")
		b.WriteString(renderRoute(roles, m.depth, m.avail, rw))
	} else {
		id := comboID(m.sel)
		if base, ok := m.generated[id]; ok {
			_, roles := splitMeta(base)
			roles = applyAdvisor(roles, m.sel["advisor"], m.sel["lane"])
			// "will launch" summary — what Enter does, before you press it.
			parts := []string{fmt.Sprintf("%d roles", len(roles))}
			if m.sel["fast"] == "on" && m.sel["lane"] != "claude-only" {
				parts = append(parts, "priority tier")
			}
			if m.sel["advisor"] != "off" {
				parts = append(parts, "advisor "+m.sel["advisor"])
			}
			acc := lipgloss.NewStyle().Foreground(lipgloss.Color(m.accent())).Bold(true)
			b.WriteString(acc.Render("⏎ launches") + stDim.Render("  "+strings.Join(parts, " · ")) + "\n\n")
			// meta line rebuilt from the facets, so it always reflects the
			// advisor dial and fast toggle (both live outside the baked grid).
			line := stDim.Render("thinking " + m.sel["thinking"] + " · fallback on · advisor " + m.sel["advisor"])
			if m.sel["lane"] != "claude-only" {
				blue := lipgloss.NewStyle().Foreground(lipgloss.Color("#62a7ff"))
				state := stDim.Render("off")
				if m.sel["fast"] == "on" {
					state = blue.Render("on")
				}
				line += stDim.Render(" · ") + blue.Render(m.glyphs["fast"]) + stDim.Render(" fast ") + state
			}
			b.WriteString(line + "\n" + rule + "\n")
			b.WriteString(renderRoute(roles, m.depth, m.avail, rw))
		} else {
			b.WriteString(stDim.Render("no profile for this combination") + "\n")
		}
	}
	// clip (don't wrap) to pane width — renderRoute already wrapped the chains.
	content := lipgloss.NewStyle().MaxWidth(m.vp.Width).Render(b.String())
	m.vp.SetContent(content)
	m.vp.GotoTop()
}

// footer is the pinned bottom block: the usage panel (if any) then the controls
// help, each under a rule. Built once here so relayout and View stay in sync.
func (m *model) footer() string {
	rule := stDim.Render(strings.Repeat("─", m.w))
	var parts []string
	if p := m.usagePanel(); p != "" {
		parts = append(parts, rule, p)
	}
	parts = append(parts, rule, "  "+m.help.View(keys))
	return strings.Join(parts, "\n")
}

func (m *model) relayout() {
	pw := m.w - m.listW() - 3
	if m.mode() == modeCollapsed {
		pw = m.w
	}
	if pw < 10 {
		pw = 10
	}
	m.help.Width = m.w
	vh := m.h - lipgloss.Height(m.footer())
	if vh < 3 {
		vh = 3
	}
	if !m.rdy {
		m.vp = viewport.New(pw, vh)
		m.rdy = true
	} else {
		m.vp.Width, m.vp.Height = pw, vh
	}
	m.syncPreview()
}

func (m model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.w, m.h = msg.Width, msg.Height
		m.relayout()
	case usageMsg:
		m.avail = availability(msg)
		m.fetching = false
		m.nextRefresh = time.Now().Add(refreshEvery)
		m.relayout()
	case refreshTickMsg:
		// re-arm the 1s tick; auto-refresh once the interval elapses.
		cmds := []tea.Cmd{tickCmd()}
		if !m.fetching && !m.nextRefresh.IsZero() && !time.Now().Before(m.nextRefresh) {
			m.fetching = true
			cmds = append(cmds, fetchUsageCmd(m.usageCmd))
		}
		return m, tea.Batch(cmds...)
	case spinner.TickMsg:
		if !m.avail.ok {
			var cmd tea.Cmd
			m.spin, cmd = m.spin.Update(msg)
			return m, cmd
		}
	case tea.KeyMsg:
		switch msg.String() {
		case "q", "esc", "ctrl+c":
			return m, tea.Quit
		case "tab":
			if m.view == pickerView {
				m.view = genView
			} else {
				m.view = pickerView
			}
			m.syncPreview()
		case "p":
			if m.w >= 62 {
				m.collapse = !m.collapse // hide/show the side preview
			} else {
				m.showResult = !m.showResult // narrow: swap list ↔ result full-screen
			}
			m.relayout()
		case "?":
			m.help.ShowAll = !m.help.ShowAll
			m.relayout() // the taller/shorter footer changes the body height
		case "f":
			m.depth = (m.depth + 1) % 2
			m.syncPreview()
		case "r":
			if m.usageCmd != "" && !m.fetching {
				m.fetching = true
				return m, fetchUsageCmd(m.usageCmd)
			}
		case "up", "k":
			m.moveUp()
		case "down", "j":
			m.moveDown()
		case "left", "h":
			if m.view == genView {
				m.cycleFacet(-1)
			}
		case "right", "l":
			if m.view == genView {
				m.cycleFacet(1)
			}
		case "enter":
			if m.view == pickerView {
				m.chosen = m.profiles[m.cursor].exe
			} else {
				m.genConfig = m.genConfigYAML()
			}
			return m, tea.Quit
		}
	case tea.MouseMsg:
		switch msg.Button {
		case tea.MouseButtonWheelUp:
			m.vp.LineUp(3)
		case tea.MouseButtonWheelDown:
			m.vp.LineDown(3)
		}
	}
	return m, nil
}

func (m *model) moveUp() {
	if m.view == pickerView {
		if m.cursor > 0 {
			m.cursor--
			m.syncPreview()
		}
	} else if m.fcur > 0 {
		m.fcur--
	}
}
func (m *model) moveDown() {
	if m.view == pickerView {
		if m.cursor < len(m.profiles)-1 {
			m.cursor++
			m.syncPreview()
		}
	} else if m.fcur < len(m.visibleFacets())-1 {
		m.fcur++
	}
}
func (m *model) cycleFacet(dir int) {
	vf := m.visibleFacets()
	if m.fcur >= len(vf) {
		m.fcur = len(vf) - 1
	}
	f := vf[m.fcur]
	cur := m.sel[f.key]
	idx := 0
	for i, v := range f.values {
		if v == cur {
			idx = i
		}
	}
	idx = (idx + dir + len(f.values)) % len(f.values)
	m.sel[f.key] = f.values[idx]
	// changing the lane can hide/show facets; keep the cursor in range.
	if nv := len(m.visibleFacets()); m.fcur >= nv {
		m.fcur = nv - 1
	}
	m.syncPreview()
}

func (m model) previewPane() string {
	return lipgloss.NewStyle().
		Border(lipgloss.NormalBorder(), false, false, false, true).
		BorderForeground(lipgloss.Color(cBord)).PaddingLeft(2).
		Width(m.w - m.listW() - 3).Height(m.vp.Height).
		Render(m.vp.View())
}

// accent is the context colour — the selected lane in the generator, or the
// focused profile's lane colour in the picker. Blue / purple / orange.
func (m model) accent() string {
	if m.view == genView {
		return laneColor(m.sel["lane"])
	}
	if m.cursor < len(m.profiles) {
		return m.profiles[m.cursor].color
	}
	return cAcc
}

// sectionTabs is the prominent generator⇄profiles switcher at the top of the
// left column — the active section is an accent pill, so Tab's effect is clear.
func (m model) sectionTabs() string {
	acc := m.accent()
	pill := func(label string, active bool) string {
		s := lipgloss.NewStyle().Padding(0, 1)
		if active {
			return s.Background(lipgloss.Color(acc)).Foreground(lipgloss.Color("#12161d")).Bold(true).Render(label)
		}
		return s.Foreground(lipgloss.Color(cDim)).Render(label)
	}
	return pill("generator", m.view == genView) +
		lipgloss.NewStyle().Foreground(lipgloss.Color(cGrp)).Render(" ⇄ ") +
		pill("profiles", m.view == pickerView)
}

// windowList clips a list to h lines, scrolled to keep the cursor visible, fixes
// the width, and appends a 1-column scrollbar (blank when everything fits) — so
// the column is always exactly h lines tall and w wide, and shows its scroll pos.
func windowList(lines []string, cursor, h, w int) string {
	if h < 1 {
		h = 1
	}
	total := len(lines)
	start := 0
	if total > h {
		if cursor >= h {
			start = cursor - h + 1
		}
		if start+h > total {
			start = total - h
		}
		if start < 0 {
			start = 0
		}
	}
	end := start + h
	if end > total {
		end = total
	}
	vis := append([]string(nil), lines[start:end]...)
	for len(vis) < h { // pad so the column is exactly h tall
		vis = append(vis, "")
	}
	lw := w - 1 // reserve a column for the scrollbar
	list := lipgloss.NewStyle().Width(lw).MaxWidth(lw).Render(strings.Join(vis, "\n"))
	return lipgloss.JoinHorizontal(lipgloss.Top, list, scrollbar(total, h, start))
}

// scrollbar renders a 1-column, h-line track with a proportional thumb; when the
// content fits (total ≤ h) it is a blank column, keeping the layout width stable.
func scrollbar(total, h, start int) string {
	track := stDim.Render("│")
	thumbCh := lipgloss.NewStyle().Foreground(lipgloss.Color(cHead)).Render("┃")
	pos, thumb := -1, 0
	if total > h {
		thumb = h * h / total
		if thumb < 1 {
			thumb = 1
		}
		pos = start * h / total
		if pos+thumb > h {
			pos = h - thumb
		}
	}
	var b strings.Builder
	for i := 0; i < h; i++ {
		switch {
		case total <= h:
			b.WriteString(" ")
		case i >= pos && i < pos+thumb:
			b.WriteString(thumbCh)
		default:
			b.WriteString(track)
		}
		if i < h-1 {
			b.WriteString("\n")
		}
	}
	return b.String()
}

func (m model) leftColumn(full bool) string {
	w := m.listW()
	if full {
		w = m.w
	}
	var body []string
	var bcur int
	if m.view == pickerView {
		body, bcur = m.pickerLines(true, w)
	} else {
		body, bcur = m.genLines(true)
	}
	// the tab switcher + a blank line stay pinned; only the body scrolls.
	head := m.sectionTabs() + "\n\n"
	bodyH := m.vp.Height - 2
	if bodyH < 1 {
		bodyH = 1
	}
	return head + windowList(body, bcur, bodyH, w)
}

func (m model) View() string {
	if !m.rdy {
		return "loading…"
	}
	foot := m.footer()
	bodyH := m.h - lipgloss.Height(foot)
	if bodyH < 1 {
		bodyH = 1
	}
	var content string
	if m.mode() == modeCollapsed {
		if m.showResult && m.w < 62 {
			content = m.vp.View()
		} else {
			content = m.leftColumn(true)
		}
	} else {
		content = lipgloss.JoinHorizontal(lipgloss.Top, m.leftColumn(false), m.previewPane())
	}
	// Pin the body into a fixed box (top-left) with lipgloss, then clip: any
	// stray overflow (e.g. a glyph a terminal renders wider than measured) is
	// absorbed here, never pushing the pinned footer off-screen.
	body := lipgloss.NewStyle().MaxHeight(bodyH).Render(
		lipgloss.Place(m.w, bodyH, lipgloss.Left, lipgloss.Top, content))
	return lipgloss.NewStyle().MaxWidth(m.w).MaxHeight(m.h).Render(
		lipgloss.JoinVertical(lipgloss.Left, body, foot))
}

func (m model) pickerLines(focused bool, w int) ([]string, int) {
	trunc := lipgloss.NewStyle().MaxWidth(w).Inline(true)
	var lines []string
	cursor := 0
	lastGroup := ""
	for i, p := range m.profiles {
		if p.group != lastGroup {
			lines = append(lines, stGrp.Render(p.group))
			lastGroup = p.group
		}
		mark := "  "
		switch m.avail.impact(m.routes[p.name]) {
		case "broken":
			mark = stBrk.Render(gBroken + " ")
		case "degraded":
			mark = stWarn.Render(gWarn + " ")
		}
		nameCol := p.color
		blurb := flavorize(p.blurb)
		if !focused {
			nameCol, blurb = cDim, stDim.Render(p.blurb)
		}
		// selection is a pointer (like the generator), not a background block.
		ptr := "  "
		if i == m.cursor {
			cursor = len(lines)
			if focused {
				ptr = lipgloss.NewStyle().Foreground(lipgloss.Color(m.accent())).Bold(true).Render("▸ ")
			} else {
				ptr = stDim.Render("▸ ")
			}
		}
		gly := lipgloss.NewStyle().Foreground(lipgloss.Color(nameCol)).Width(2).Render(p.glyph)
		nm := lipgloss.NewStyle().Foreground(lipgloss.Color(nameCol)).Bold(focused).Render(pad(p.name, 5))
		row := trunc.Render(ptr + mark + gly + nm + stDim.Render("— ") + blurb)
		lines = append(lines, row)
	}
	return lines, cursor
}

func (m model) genLines(focused bool) ([]string, int) {
	acc := m.accent()
	var lines []string
	cursor := 0
	for i, f := range m.visibleFacets() {
		onRow := i == m.fcur && focused
		glyCol := laneColor(m.sel["lane"])
		if !focused {
			glyCol = cDim
		}
		gly := lipgloss.NewStyle().Foreground(lipgloss.Color(glyCol)).Width(2).Render(f.glyph)
		ptr := "  "
		if onRow {
			ptr = lipgloss.NewStyle().Foreground(lipgloss.Color(acc)).Render("▸ ")
			cursor = len(lines)
		}
		row := fmt.Sprintf("%s%s%s", ptr, gly, stDim.Render(pad(f.key, 9)))
		for _, v := range f.values {
			switch {
			case v == m.sel[f.key]:
				col := acc
				if f.key == "lane" {
					col = laneColor(v)
				} else if (f.key == "spark" || f.key == "fable") && v == "on" {
					col = cGreen
				}
				if !focused {
					col = cGrp // grayed but legible when the section is unfocused
				}
				st := lipgloss.NewStyle().Foreground(lipgloss.Color(col)).Bold(focused)
				if onRow { // the cursor sits on the selected value of the focused row
					st = st.Background(lipgloss.Color(cSelBg))
				}
				row += "  " + st.Render(" "+v+" ")
			default:
				row += "   " + stDim.Render(v)
			}
		}
		switch {
		case focused && (f.key == "fable" || f.key == "spark") && m.sel[f.key] == "on":
			bkt, lbl := "claude-fable", "Fable"
			if f.key == "spark" {
				bkt, lbl = "codex-spark", "Spark"
			}
			if m.avail.down(bkt) {
				w := lbl + " maxed · " + gReset + " " + fmtReset(m.avail.reset[bkt])
				if m.avail.bucket[bkt] == "unauthed" {
					w = lbl + " unavailable"
				}
				row += "   " + stWarn.Render(gWarn+" "+w+" — no usage left")
			}
		case focused && f.key == "fast" && m.sel["fast"] == "on":
			row += "   " + stDim.Render("priority service tier — quicker OpenAI replies")
		}
		lines = append(lines, row)
	}
	return lines, cursor
}

func pad(s string, n int) string {
	for len(s) < n {
		s += " "
	}
	return s
}

func main() {
	profiles := loadProfiles(os.Getenv("CODE_PROFILES"))
	if len(profiles) == 0 {
		fmt.Fprintln(os.Stderr, "code: no profiles (CODE_PROFILES)")
		os.Exit(2)
	}
	// Facet glyphs are intrinsic to the generator, so the binary carries sane
	// defaults (Nerd Font, FA range). CODE_FACET_GLYPHS may override any of them.
	//   lane ⇄  model ⚙  thinking 💡  spark 🚀  fable 📖  fast ⚡
	glyphs := map[string]string{
		"lane": "", "model": "", "thinking": "", "advisor": "",
		"spark": "", "fable": "", "fast": "",
	}
	for _, kv := range strings.Split(os.Getenv("CODE_FACET_GLYPHS"), ",") {
		if p := strings.SplitN(kv, "=", 2); len(p) == 2 && p[1] != "" {
			glyphs[p[0]] = p[1]
		}
	}
	sp := spinner.New()
	sp.Spinner = spinner.Dot
	m := model{
		profiles:  profiles,
		routes:    loadBlocks(os.Getenv("CODE_ROUTES")),
		generated: loadBlocks(os.Getenv("CODE_GENERATED")),
		avail:     availability{bucket: map[string]string{}, reset: map[string]int64{}},
		usageCmd:  os.Getenv("CODE_USAGE"),
		spin:      sp,
		help:      help.New(),
		glyphs:    glyphs,
		view:      genView, // generator is the default view
		facets:    facetDefs(glyphs),
		sel:       map[string]string{"lane": "mixed", "model": "normal", "thinking": "medium", "advisor": "glance", "spark": "on", "fable": "off", "fast": "off"},
	}
	final, err := tea.NewProgram(m, tea.WithAltScreen(), tea.WithMouseCellMotion()).Run()
	if err != nil {
		fmt.Fprintln(os.Stderr, "code:", err)
		os.Exit(1)
	}
	fm, _ := final.(model)
	if fm.chosen != "" {
		args := append([]string{fm.chosen}, os.Args[1:]...)
		if err := syscall.Exec(fm.chosen, args, os.Environ()); err != nil {
			fmt.Fprintln(os.Stderr, "code: exec:", err)
			os.Exit(1)
		}
	}
	if fm.genConfig != "" {
		launchGenerated(fm.genConfig)
	}
}

// launchGenerated writes the generated routing to a temp file and execs the
// managed omp wrapper with it as a single one-shot --config. The wrapper itself
// supplies the platform extensions, managed defaults, and policy (and caps the
// overlay), so we must NOT re-layer defaults/policy here — doing so both
// double-applies them and breaks when their paths aren't valid from the cwd.
func launchGenerated(cfg string) {
	tmp, err := os.CreateTemp("", "code-gen-*.yml")
	if err != nil {
		fmt.Fprintln(os.Stderr, "code:", err)
		os.Exit(1)
	}
	tmp.WriteString(cfg)
	tmp.Close()
	omp := os.Getenv("CODE_OMP")
	if omp == "" {
		omp = "omp"
	}
	path, err := exec.LookPath(omp)
	if err != nil {
		fmt.Fprintln(os.Stderr, "code: omp not found:", err)
		os.Exit(1)
	}
	args := append([]string{path, "--config", tmp.Name()}, os.Args[1:]...)
	if err := syscall.Exec(path, args, os.Environ()); err != nil {
		fmt.Fprintln(os.Stderr, "code: exec:", err)
		os.Exit(1)
	}
}
